    /// Create a new tree with a mandatory comparison function and an optional free function.
    pub fn bostree_new(
        cmp_function: BOSTreeCmpFunction,
        free_function: Option<BOSTreeFreeFunction>,
    ) -> Self {
        BOSTree {
            root_node: None,
            cmp_function,
            free_function,
        }
    }

    fn child_depth(child: &Option<Rc<RefCell<BOSNode>>>) -> u32 {
        child.as_ref().map_or(0, |n| n.borrow().depth + 1)
    }

    fn subtree_count(child: &Option<Rc<RefCell<BOSNode>>>) -> u32 {
        child
            .as_ref()
            .map_or(0, |n| n.borrow().left_child_count + n.borrow().right_child_count + 1)
    }

    fn update_node(node: &Rc<RefCell<BOSNode>>) {
        let (left_depth, right_depth, left_count, right_count) = {
            let n = node.borrow();
            (
                Self::child_depth(&n.left_child_node),
                Self::child_depth(&n.right_child_node),
                Self::subtree_count(&n.left_child_node),
                Self::subtree_count(&n.right_child_node),
            )
        };
        let mut n = node.borrow_mut();
        n.left_child_count = left_count;
        n.right_child_count = right_count;
        n.depth = max(left_depth, right_depth);
    }

    fn balance(node: &Rc<RefCell<BOSNode>>) -> i32 {
        let n = node.borrow();
        Self::child_depth(&n.right_child_node) as i32 - Self::child_depth(&n.left_child_node) as i32
