                let mut n = target.borrow_mut();
                let mut s = successor.borrow_mut();
                std::mem::swap(&mut n.key, &mut s.key);
                std::mem::swap(&mut n.data, &mut s.data);
            }
            target = successor;
        }

        let child = {
            let t = target.borrow();
            if t.left_child_node.is_some() {
                t.left_child_node.clone()
            } else {
                t.right_child_node.clone()
            }
        };
        let parent = Self::parent(&target);

        if let Some(ref c) = child {
            c.borrow_mut().parent_node = parent.as_ref().map(Rc::downgrade);
        }

        if let Some(ref p) = parent {
            let target_was_left = Self::is_left_child_of(&target, p);
            if target_was_left {
                p.borrow_mut().left_child_node = child.clone();
            } else {
                p.borrow_mut().right_child_node = child.clone();
            }
        } else {
            self.root_node = child.clone();
        }

