            let mut t = target.borrow_mut();
            t.left_child_node = None;
            t.right_child_node = None;
            t.parent_node = None;
            t.left_child_count = 0;
            t.right_child_count = 0;
            t.depth = 0;
            t.weak_ref_node_valid = 0;
        }

