    pub fn bostree_print(&self) {
        fn print_node(node: &Option<Rc<RefCell<BOSNode>>>, indent: usize) {
            if let Some(n) = node {
                let nb = n.borrow();
                print_node(&nb.right_child_node, indent + 4);
                println!(
                    "{:indent$}{} (l={}, r={}, d={})",
                    "",
                    nb.key,
                    nb.left_child_count,
                    nb.right_child_count,
                    nb.depth,
                    indent = indent
                );
                print_node(&nb.left_child_node, indent + 4);
            }
        }
        print_node(&self.root_node, 0);
    }
