/// Increase the weak reference count for a node and return the node.
pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
    let mut n = node.borrow_mut();
    n.weak_ref_count = n.weak_ref_count.saturating_add(1);
    node.clone()
}

/// Return the next node in an in-order traversal.
pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(mut cur) = node.borrow().right_child_node.clone() {
        loop {
            let left = cur.borrow().left_child_node.clone();
            if let Some(l) = left {
                cur = l;
            } else {
                return Some(cur);
            }
        }
    }

    let mut cur = node.clone();
    while let Some(parent) = BOSTree::parent(&cur) {
        if BOSTree::is_left_child_of(&cur, &parent) {
            return Some(parent);
        }
        cur = parent;
    }
    None
}

/// Return the previous node in an in-order traversal.
pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
    if let Some(mut cur) = node.borrow().left_child_node.clone() {
        loop {
            let right = cur.borrow().right_child_node.clone();
            if let Some(r) = right {
                cur = r;
            } else {
                return Some(cur);
            }
        }
    }

    let mut cur = node.clone();
    while let Some(parent) = BOSTree::parent(&cur) {
        if !BOSTree::is_left_child_of(&cur, &parent) {
            return Some(parent);
        }
        cur = parent;
    }
    None
}

/// Return the rank (in-order index) of the given node.
pub fn bostree_rank(node: &Rc<RefCell<BOSNode>>) -> u32 {
    let mut rank = node.borrow().left_child_count;
    let mut cur = node.clone();
    while let Some(parent) = BOSTree::parent(&cur) {
        if !BOSTree::is_left_child_of(&cur, &parent) {
            rank += parent.borrow().left_child_count + 1;
        }
        cur = parent;
    }
    rank
}
